// ── APLANAR RESULTADOS (Rama 1: Noticias principales) ────────────────────────
// REGLA CLAVE: solo pasan artículos que mencionen "Adecoagro" explícitamente
// en el título o snippet. Sin excepción.
// Además: máx. 1 resultado por dominio de agregador financiero (Yahoo Finance,
// StockAnalysis, etc.) para evitar redundancia de páginas de cotización.
// ─────────────────────────────────────────────────────────────────────────────

const items = $input.all();
const results = [];

const socialBlacklist = [
  'instagram.com', 'facebook.com', 'youtube.com',
  'tiktok.com', 'twitter.com', 'x.com', 'linkedin.com', 'pinterest.com', 'threads.net'
];

// Dominios de agregadores financieros: solo se admite 1 resultado total
// (múltiples páginas del precio de AGRO no aportan valor editorial)
const financialAggregators = [
  'finance.yahoo.com', 'stockanalysis.com', 'stocktitan.net', 'thestreet.com',
  'marketwatch.com', 'macrotrends.net', 'wisesheets.io', 'simplywall.st',
  'gurufocus.com', 'finviz.com', 'barchart.com', 'stockcharts.com'
];

// Patrones de URL que son portadas/categorías genéricas (no artículos reales)
const isPortalPage = (url) => {
  // /tag/slug, /category/slug, /etiqueta/slug, /autor/slug, etc.
  if (/\/(tag|category|etiqueta|topics?|labels?|autor(?:es)?|author|buscar|search)\/[^?#]*/i.test(url)) return true;
  // Secciones genéricas al final
  if (/\/(noticias|economia|agro|campo|finanzas|mercados|bursatil|noticias-agro)\/?(?:\?.*)?$/i.test(url)) return true;
  // Páginas de cotización de bolsa: /quote/TICKER o /chart/
  if (/\/(?:quote|chart|symbol)\/[^?#]*/i.test(url)) return true;
  // URLs template/ejemplo (ej: clarin.com/newsletter/example/...)
  if (/\/(?:newsletter\/example|newsletter\/template|\/example\/)/i.test(url)) return true;
  // Raíz de dominio sin path real
  if (/^https?:\/\/[^\/]+\/?(?:\?.*)?$/.test(url)) return true;
  return false;
};

const normalizar = (s) => (s||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');

// Dominios prioritarios desde Config
const sitiosPrioritarios = ($('Config').item.json.sitios_prioritarios || '')
  .split(',').map(d => d.trim()).filter(Boolean);

let financialCount = 0;  // contador de páginas de cotización ya incluidas
const seenUrls = new Set();

for (const item of items) {
  const organic = item.json.organic || [];
  for (const result of organic) {
    const link = result.link || '';
    const titulo  = result.title   || '';
    const snippet = result.snippet || '';

    // Descartar redes sociales
    if (socialBlacklist.some(d => link.includes(d))) continue;

    // Descartar portadas de portales
    if (isPortalPage(link)) continue;

    // Descartar duplicados por URL
    if (seenUrls.has(link)) continue;

    // REGLA PRINCIPAL: el título o snippet debe mencionar "Adecoagro" explícitamente
    const texto = normalizar(titulo + ' ' + snippet);
    if (!texto.includes('adecoagro')) continue;

    // Límite de 1 página de agregador financiero (cotizaciones)
    const esFinancial = financialAggregators.some(d => link.includes(d));
    if (esFinancial) {
      if (financialCount >= 1) continue;  // ya tenemos la cotización, descartar
      financialCount++;
    }

    seenUrls.add(link);
    const esPrioritario = sitiosPrioritarios.some(d => link.includes(d));

    results.push({
      json: {
        url:           link,
        title:         titulo,
        snippet:       snippet,
        source:        'Web',
        date:          result.date || 'Reciente',
        es_prioritario: esPrioritario,
        es_financial:  esFinancial
      }
    });
  }
}

// Prioritarios primero, luego el resto
results.sort((a, b) => (b.json.es_prioritario ? 1 : 0) - (a.json.es_prioritario ? 1 : 0));
return results;

// ── PARSEAR SCRAPER (Rama 1: Noticias principales) ───────────────────────────
// Recibe el stdout del scraper Python + datos originales de Aplanar Resultados.
// Valida si el scraper extrajo texto útil; si no, usa el snippet de Google.
// Produce el esquema unificado que usa el resto del workflow.
// ─────────────────────────────────────────────────────────────────────────────

// 1. Parsear la salida JSON del script Python
const pythonOutput = JSON.parse($input.item.json.stdout);

// 2. Recuperar los datos originales del resultado de Google (título, url, snippet)
const originalData = $("Aplanar Resultados").item.json;

// 3. Validar calidad del scraping:
//    - El scraper debe haber tenido éxito (status === 'success')
//    - El texto extraído debe mencionar "adecoagro" (evita leer el footer u otra nota)
const scraperOk    = pythonOutput.status === 'success' && pythonOutput.text;
const esRelevante  = scraperOk && pythonOutput.text.toLowerCase().includes('adecoagro');

let contenidoFinal, fuenteFinal, statusFinal;

if (scraperOk && esRelevante) {
  // CASO A — Éxito total: el scraper leyó la nota y menciona a la empresa
  contenidoFinal = pythonOutput.text;
  fuenteFinal    = 'Scraper Full';
  statusFinal    = 'success';
} else {
  // CASO B — Fallback: scraper falló o el texto no es relevante → usar snippet de Google
  // El snippet siempre es pertinente porque Google ya filtró por la query de la empresa
  contenidoFinal = originalData.snippet || '';
  fuenteFinal    = 'Google Snippet (Fallback)';
  statusFinal    = 'fallback';
}

// 4. Hash de contenido para deduplicación (mismo campo en todos los ramas)
const content_hash = pythonOutput.content_hash
  || 'web_' + originalData.title.replace(/\s+/g, '').toLowerCase().slice(0, 40);

// 5. Retornar esquema unificado (igual al de Rama 2 y Rama 3)
return {
  json: {
    url:          originalData.url,       // campo unificado (no "link")
    titulo:       originalData.title,
    contenido:    contenidoFinal,          // campo unificado (no "text")
    content_hash: content_hash,            // campo unificado (no "hash")
    tipo_fuente:  'web',                   // se setea aquí; el nodo Set posterior también lo pone (redundante pero inofensivo)
    fecha:        originalData.date || '',
    fuente_scraper: fuenteFinal,
    status_scraper: statusFinal
  }
};

