parameters.jsCode:
// ── NORMALIZAR SOCIAL (Rama 2: Redes sociales) ───────────────────────────────
// REGLA CLAVE: solo pasan posts que mencionen "adecoagro" (o AGRO como ticker)
// explícitamente en título o snippet. No alcanza con palabras del sector.
// ─────────────────────────────────────────────────────────────────────────────

// Dominios de e-commerce y spam
const dominiosEcommerce = [
  'mercadolibre', 'mercadolivre', 'amazon', 'pedidosya', 'rappi',
  'supermercado', 'elcondor', 'walmart', 'coto.com', 'disco.com',
  'jumbo.com', 'carrefour', 'makro', 'easy.com', 'fravega'
];

const normalizar = (s) => (s||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');

const resultado = [];
const seenHashes = new Set();

for (const item of $input.all()) {
  const rawUrl   = item.json.link || '';
  const titulo   = item.json.title   || '';
  const snippet  = item.json.snippet || '';
  const urlLower = rawUrl.toLowerCase();

  // A. Descartar e-commerce y spam
  if (dominiosEcommerce.some(d => urlLower.includes(d))) continue;

  // B. REGLA PRINCIPAL: el título o snippet debe mencionar "adecoagro" explícitamente
  //    También aceptar ticker "agro" como palabra independiente (ej: "$AGRO" o "AGRO stock")
  const textoNorm = normalizar(titulo + ' ' + snippet);
  const mencionaAdecoagro = textoNorm.includes('adecoagro');
  const mencionaTickerAgro = /\bagro\b/.test(textoNorm) &&
    (textoNorm.includes('accion') || textoNorm.includes('stock') || textoNorm.includes('ticker') ||
     textoNorm.includes('bolsa') || textoNorm.includes('inversi') || textoNorm.includes('adr'));

  if (!mencionaAdecoagro && !mencionaTickerAgro) continue;

  // C. Hash para deduplicación
  let hashNum = 0;
  for (let i = 0; i < rawUrl.length; i++) {
    hashNum = ((hashNum << 5) - hashNum) + rawUrl.charCodeAt(i);
    hashNum |= 0;
  }
  const content_hash = 'soc_' + Math.abs(hashNum).toString();
  if (seenHashes.has(content_hash)) continue;
  seenHashes.add(content_hash);

  resultado.push({
    json: {
      url:          rawUrl,
      titulo:       titulo,
      contenido:    snippet,
      content_hash: content_hash,
      tipo_fuente:  'social',
      fecha:        item.json.date || '',
      empresa:      'Adecoagro'
    }
  });
}

return resultado;

// ── APLANAR RESULTADOS 1 (Rama 3: Empresas asociadas) ────────────────────────
// Recibe los resultados de Serper para cada empresa asociada.
// Aplica filtros en cascada: basura técnica → veneno global → blacklist contextual
// NUEVO: para empresas con nombre ambiguo, exige al menos 1 keyword positiva.
// ─────────────────────────────────────────────────────────────────────────────

let resultadosAcumulados = [];

// Agregadores financieros: max 1 resultado por empresa
const financialAggregators = [
  'finance.yahoo.com', 'stockanalysis.com', 'stocktitan.net', 'thestreet.com',
  'marketwatch.com', 'macrotrends.net', 'wisesheets.io', 'simplywall.st',
  'gurufocus.com', 'finviz.com', 'barchart.com', 'stockcharts.com',
  'investing.com', 'tradingview.com'
];
const finCountPerEmpresa = {};

const normalizar = (str) =>
  (str || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

// ── 1. DOMINIOS TÉCNICOS DESCARTADOS ──
const dominiosBasura = [
  // Redes sociales (manejadas por Rama 2)
  'facebook.com','instagram.com','twitter.com','x.com',
  'tiktok.com','linkedin.com','youtube.com','pinterest.com','jw.org',
  // E-commerce y supermercados (no son fuentes de noticias)
  'mercadolibre','mercadolivre','amazon.com','pedidosya','rappi.com',
  'supermercado','elcondor','walmart.com','coto.com','disco.com',
  'jumbo.com','carrefour','makro.com','easy.com','fravega.com',
  'tiendamia','linikers','tiendanube'
];

// ── 2. VENENO GLOBAL (aplica a todas las empresas) ──
const palabrasVenenoGlobal = [
  'horoscopo','signos del zodiaco','tarot','sexo','xxx',
  'casino online','juegos de azar','loteria'
];

// ── 3. BLACKLISTS CONTEXTUALES: términos que delatan homonimia (filtro NEGATIVO) ──
const blacklistsContextuales = {
  "apostoles": [
    // Localidad de Misiones
    "semana santa","pesanke","turismo","municipio","intendente",
    "localidad","capital provincial","clima","pronostico","tiempo",
    "medicamentos","hospital","farmacia","vecinos","feligreses",
    // Motín/policiales
    "motin","preso","detenido","comisaria","juzgado","penal"
  ],
  "pilaga": [
    "etnia","aborigen","indigena","wichi","qom","comunidad originaria",
    "bano la estrella","las lomitas","desarrollo humano",
    "asistencia social","ministerio","riacho","caja de prevision"
  ],
  "la carolina": [
    "turismo","cabanas","trekking","vacaciones","sierra","gruta","spa",
    "mina de oro","festival","folklore","pena criolla",
    // Ecuador
    "quito","ecuador","organismo","policia nacional"
  ],
  "angelita": [
    "nodal","christian","yanina","lam","angel de brito",
    "chimentos","nieta","beba","inti","tini","farandula"
  ],
  "simoneta": [
    "borbon","familia real","reina","trono","telenovela","actriz","televisa"
  ],
  "el orden": [
    "orden mundial","orden global","filosofia","politico","seguridad publica",
    "fuerza de seguridad","gobernador","presidente","congreso"
  ],
  "la lacteo": [
    // Evitar noticias de lácteos europeos o genéricos sin relación con la empresa
    "castilla","leon","galicia","espana","europa","nueva zelanda","uruguay exporta",
    "estudio clinico","nutricion infantil"
  ],
  "apostoles": [
    // Alias por si viene normalizado distinto
    "semana santa","pesanke","turismo","municipio","pronostico"
  ]
};

// ── 4. KEYWORDS POSITIVAS: empresas ambiguas DEBEN mencionar al menos una ──
// Si el snippet no menciona ninguna de estas palabras, la noticia no es del rubro.
const keywordsPositivas = {
  "apostoles":   ["lacteo","leche","yogur","queso","crema","manteca","dairy","adecoagro","agro","campo","hacienda"],
  "la lacteo":   ["argentina","adecoagro","industria lactea argentina"],
  "el orden":    ["campo","agro","adecoagro","misiones","corrientes","entre rios","granos","hacienda"],
  "angelita":    ["agro","campo","adecoagro","granja","hacienda","lacteo","soja","girasol"],
  "simoneta":    ["agro","campo","adecoagro","hacienda","bovino","granos"],
  "pilaga":      ["azucar","cana","agro","adecoagro","campo","ingenio","hacienda"],
  "tether":      ["adecoagro"],
  "la carolina": ["agro","campo","adecoagro","hacienda","bovino","soja","granos"],
  // Profertil puede coincidir con noticias genéricas de fertilizantes globales
  "profertil":   ["fertilizante","urea","nitrogenado","amoniaco","agro","campo","adecoagro","planta","produccion","argentina"],
};

// ── 4b. FILTRO DE PORTADAS: descartar URLs que sean categorías, tags o portadas ──
const isPortalPage = (url) => {
  // Captura /tag/slug, /category/slug, /etiqueta/slug, /autor/slug, etc.
  if (/\/(tag|category|etiqueta|topics?|labels?|autor(?:es)?|author|buscar|search)\/[^?#]*/i.test(url)) return true;
  // Captura URLs que terminan en secciones genéricas
  if (/\/(noticias|economia|agro|campo|finanzas|mercados|bursatil|noticias-agro)\/?(?:\?.*)?$/i.test(url)) return true;
  // Captura raíces de dominio sin path real
  if (/^https?:\/\/[^\/]+\/?(?:\?.*)?$/.test(url)) return true;
  return false;
};

// ── 5. VIP: estas keywords hacen pasar el item sin importar los filtros ──
// Quitamos "tether" del VIP — ya tiene su propio filtro positivo arriba
const keywordsVitales = [
  'adecoagro','profertil','bioceres',
  'fertilizante','productora','acreedores','inversion',
  'mercado de capitales','campo argentino'
];

for (const item of items) {
  const organicResults = item.json.organic || [];

  // Recuperar nombre de empresa — priorizar campo empresa_asociada del item original
  let empresaOriginal = item.json.empresa_asociada || 'Empresa Desconocida';
  if (empresaOriginal === 'Empresa Desconocida') {
    // Fallback: extraer del campo q de searchParameters
    const match = (item.json.searchParameters?.q || '').match(/"([^"]+)"/);
    if (match && match[1]) {
      empresaOriginal = match[1];
    } else {
      empresaOriginal = (item.json.searchParameters?.q || '')
        .split(' ').find(w => w.length > 4 && !['noticias','argentina','agro','campo','adecoagro','site:','OR'].includes(w.toLowerCase())) || 'Empresa';
    }
  }

  const empresaNorm = normalizar(empresaOriginal);
  if (organicResults.length === 0) continue;

  const filtrados = organicResults.filter(noticia => {
    const link       = (noticia.link || '').toLowerCase();
    const titulo     = normalizar(noticia.title);
    const snippet    = normalizar(noticia.snippet);
    const textoTotal = titulo + ' ' + snippet;

    // A. Dominios técnicos descartados
    if (dominiosBasura.some(d => link.includes(d))) return false;

    // A2. Descartar portadas/categorías de portales (sin artículo real)
    if (isPortalPage(link)) return false;

    // B. Veneno global
    if (palabrasVenenoGlobal.some(p => textoTotal.includes(normalizar(p)))) return false;

    // C. VIP — pasa sin más checks (excepto Tether que tiene su filtro positivo)
    const esVip = keywordsVitales.some(k => textoTotal.includes(normalizar(k)));
    if (esVip && empresaNorm !== 'tether') return true;

    // D. Blacklist contextual según empresa
    const reglaBlack = Object.keys(blacklistsContextuales)
      .find(k => empresaNorm.includes(k) || k.includes(empresaNorm));
    if (reglaBlack) {
      const prohibidas = blacklistsContextuales[reglaBlack];
      if (prohibidas.some(p => textoTotal.includes(normalizar(p)))) return false;
    }

    // E. NUEVO — Keywords positivas: para empresas ambiguas, exigir al menos 1
    const reglaPosi = Object.keys(keywordsPositivas)
      .find(k => empresaNorm.includes(k) || k.includes(empresaNorm));
    if (reglaPosi) {
      const requeridas = keywordsPositivas[reglaPosi];
      const tieneAlMenosUna = requeridas.some(p => textoTotal.includes(normalizar(p)));
      if (!tieneAlMenosUna) return false;  // No habla del rubro correcto
    }

    // F. Para Apóstoles específicamente: aunque pase keyword "leche",
    //    verificar que la URL no sea una página de producto de supermercado
    if (empresaNorm.includes('apostoles')) {
      const urlN = (noticia.link||'').toLowerCase();
      const esProducto = ['producto','shop','comprar','precio','oferta','catalogo','ficha']
        .some(p => urlN.includes(p));
      if (esProducto) return false;
    }

    return true;
  });

  // Max 1 página de cotización por empresa
  const filtradosFin = filtrados.filter(noticia => {
    const esFinancial = financialAggregators.some(d => (noticia.link||'').includes(d));
    if (!esFinancial) return true;
    finCountPerEmpresa[empresaNorm] = (finCountPerEmpresa[empresaNorm] || 0) + 1;
    return finCountPerEmpresa[empresaNorm] <= 1;
  });

  const mapeados = filtradosFin.map(noticia => ({
    json: {
      url:               noticia.link,
      titulo:            noticia.title,
      snippet:           noticia.snippet,
      source:            'Web Asociada',
      empresa:           empresaOriginal,
      fecha_publicacion: noticia.date || 'Sin fecha',
      tipo_fuente:       'web_asociada'
    }
  }));

  resultadosAcumulados.push(...mapeados);
}

return resultadosAcumulados;

// ── PARSEAR SCRAPER 1 (Rama 3: Empresas asociadas) ───────────────────────────
// Recibe stdout del scraper Python para cada URL de empresa asociada.
// Aplica filtros para descartar noticias irrelevantes (ruido de homonimias).
// A diferencia de Rama 1, incluye blacklists contextuales por empresa.
// Ahora con fallback a snippet cuando el scraper falla (igual que Rama 1).
// ─────────────────────────────────────────────────────────────────────────────

// ── PASE VIP: si el artículo menciona estas palabras, pasa sin importar nada más
// Nota: "tether" ya NO es VIP — solo pasa si menciona "adecoagro" (filtro positivo abajo)
const VIP_KEYWORDS = [
  'profertil', 'adecoagro', 'bioceres',
  'bit-cow', 'bit cow', 'moolec', 'inversión en adecoagro', 'adquisición adecoagro'
];

// ── KEYWORDS POSITIVAS sobre contenido completo (segunda pasada post-scraper) ──
// Para empresas ambiguas: si el texto completo no contiene al menos una keyword
// del rubro, descartamos — aunque haya pasado el filtro de snippet.
const CONTENT_REQUIRED = {
  'apostoles':   ['lacteo','leche','yogur','queso','crema','manteca','adecoagro'],
  'la lacteo':   ['argentina','adecoagro'],
  'el orden':    ['campo','agro','adecoagro','misiones','corrientes'],
  'angelita':    ['agro','campo','adecoagro','granja','hacienda','lacteo'],
  'simoneta':    ['agro','campo','adecoagro','hacienda','bovino'],
  'pilaga':      ['azucar','cana','agro','adecoagro','campo','ingenio'],
  'tether':      ['adecoagro'],
  'la carolina': ['agro','campo','adecoagro','hacienda','bovino'],
};

// ── BLACKLIST GLOBAL: descarta siempre, salvo que sea VIP
const GLOBAL_BLACKLIST = [
  // Crónica roja
  'motochorro', 'asalto a mano armada', 'robo calificado', 'policiales',
  'detenido', 'comisaría', 'allanamiento', 'femicidio', 'asesinato', 'cadáver',
  'siniestro vial', 'vuelco', 'choque', 'accidente de tránsito', 'inseguridad', 'heridos',
  // Salud y desastres
  'hantavirus', 'dengue', 'zika', 'vacunación', 'hospital distrital',
  'incendio', 'fuego', 'bomberos', 'llamas', 'brigadistas', 'avión hidrante',
  // Obras públicas y municipios
  'vialidad', 'bacheo', 'pavimento', 'cordón cuneta', 'red de agua potable',
  'cloacas', 'alumbrado público', 'poda', 'cronograma de pagos', 'anses',
  'licitación pública', 'apertura de sobres', 'municipio de', 'intendente',
  // Farándula y realeza
  'gran hermano', 'horóscopo', 'wanda nara', 'pampita', 'infanta', 'realeza',
  'duquesa', 'princesa', 'borbón', 'rey juan carlos', 'farándula', 'espectáculos',
  // Basura web
  'casino online', 'tragamonedas', 'avisos legales', 'política de cookies',
  'error 404', 'copyright', 'all rights reserved', 'suscríbete'
];

// ── BLACKLISTS CONTEXTUALES: ruido específico de empresas con nombre homónimo
const CONTEXTUAL_BLACKLIST = {
  'pilaga':      ['riacho', 'etnia', 'indigena', 'indígena', 'wichi', 'qom', 'aborigen', 'baño la estrella', 'las lomitas', 'comunidad originaria', 'desarrollo humano', 'asistencia social', 'entrega de módulos', 'caja de previsión', 'ministerio'],
  'la carolina': ['arroyo', 'festival', 'turismo', 'sierra', 'san luis', 'cabaña', 'alquiler', 'vacaciones', 'hotel', 'spa', 'peña', 'folklore', 'trekking', 'mina de oro', 'gruta', 'virgen'],
  'simoneta':    ['borbón', 'familia real', 'reina', 'trono', 'telenovela'],
  'angelita':    ['lam', 'yanina', 'angel de brito', 'chimentos'],
  'el orden':    ['policiales', 'muerto', 'accidente', 'hospital', 'comisaría'],
  'apostoles':   ['policiales', 'policía', 'patrulla', 'menores', 'desorientados', 'juez', 'penal', 'comisaría', 'siniestro']
};

const resultadosFinales = [];

for (const item of items) {

  // ── Parsear salida Python ──
  let datosScraper = {};
  const scraperExitOk = item.json.exitCode === 0 && item.json.stdout;

  if (scraperExitOk) {
    try { datosScraper = JSON.parse(item.json.stdout); } catch(e) { /* JSON roto */ }
  }

  // ── Recuperar datos originales de Aplanar Resultados1 (snippet, título, empresa) ──
  let datosOriginales = {};
  try {
    if (item.pairedItem !== undefined) {
      const parentItem = $('Aplanar Resultados1').itemMatching(item.pairedItem.item || item.pairedItem);
      if (parentItem && parentItem.json) datosOriginales = parentItem.json;
    }
  } catch(e) { /* no se pudo recuperar parent */ }

  const empresaOrigen = (datosOriginales.empresa || item.json.empresa || 'Desconocida').toLowerCase().trim();
  const urlOriginal   = datosOriginales.url || datosScraper.url || '';
  const tituloOrig    = datosOriginales.titulo || '';
  const snippetOrig   = datosOriginales.snippet || '';

  // ── Determinar contenido a usar ──
  const scraperTrajoTexto = datosScraper.status === 'success' && datosScraper.text && datosScraper.text.length >= 250;
  let contenidoFinal, fuenteFinal;

  if (scraperTrajoTexto) {
    contenidoFinal = datosScraper.text.length > 20000
      ? datosScraper.text.substring(0, 20000) + '... [TEXTO RECORTADO]'
      : datosScraper.text;
    fuenteFinal = 'Scraper Full';
  } else {
    // FALLBACK: usar snippet de Google si el scraper falló o trajo poco texto
    if (!snippetOrig) continue; // sin snippet ni scraper → descartar
    contenidoFinal = snippetOrig;
    fuenteFinal    = 'Google Snippet (Fallback)';
  }

  // ── Aplicar filtros de calidad (solo si NO es VIP) ──
  const textoAnalisis = (tituloOrig + ' ' + contenidoFinal).toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '');

  const esVip = VIP_KEYWORDS.some(k => textoAnalisis.includes(k));

  if (!esVip) {
    // Blacklist global
    if (GLOBAL_BLACKLIST.some(k =>
      textoAnalisis.includes(k.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, ''))
    )) continue;

    // Blacklist contextual según empresa
    const empresaNorm = empresaOrigen.normalize('NFD').replace(/[\u0300-\u036f]/g, '');
    const regla = Object.keys(CONTEXTUAL_BLACKLIST).find(k => empresaNorm.includes(k) || k.includes(empresaNorm));
    if (regla) {
      const palabras = CONTEXTUAL_BLACKLIST[regla];
      if (palabras.some(p =>
        textoAnalisis.includes(p.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, ''))
      )) continue;
    }
  }

  // ── Segunda pasada: verificar keywords positivas en contenido completo ──
  const empKey = Object.keys(CONTENT_REQUIRED)
    .find(k => empresaOrigen.includes(k) || k.includes(empresaOrigen));
  if (empKey && !esVip) {
    const contenidoNorm = contenidoFinal.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');
    const cumple = CONTENT_REQUIRED[empKey].some(p => contenidoNorm.includes(p));
    if (!cumple) continue;  // El texto completo tampoco habla del rubro → descartar
  }

  // ── Hash para deduplicación (campo unificado) ──
  const content_hash = datosScraper.content_hash
    || 'emp_' + urlOriginal.replace(/[^a-z0-9]/gi, '').toLowerCase().slice(0, 40);

  // ── Esquema unificado (igual a Ramas 1 y 2) ──
  resultadosFinales.push({
    json: {
      url:           urlOriginal,
      titulo:        tituloOrig,
      contenido:     contenidoFinal,
      content_hash:  content_hash,
      tipo_fuente:   'web_asociada',
      fecha:         datosOriginales.fecha_publicacion || '',
      empresa:       empresaOrigen,
      fuente_scraper: fuenteFinal
    }
  });
}

// ── Dedup interno por hash (por si dos fuentes trajeron la misma nota) ──
const vistos = new Set();
return resultadosFinales.filter(r => {
  if (vistos.has(r.json.content_hash)) return false;
  vistos.add(r.json.content_hash);
  return true;
});

// ── SPLIT EMPRESAS ────────────────────────────────────────────────────────────
// Queries optimizadas por empresa con contexto de sector y fuentes argentinas.
// Para nombres ambiguos se añaden restricciones de sitio y términos del rubro.
// ─────────────────────────────────────────────────────────────────────────────

const item = items[0].json;
const empresasString = item.empresas_asociadas || item.query_busqueda;

if (!empresasString) {
  throw new Error("No se encontró el campo 'empresas_asociadas' en Config.");
}

// Fuentes de medios argentinos especializados en agro/economía
const MEDIOS_ARG = 'site:infobae.com OR site:cronista.com OR site:ambito.com OR site:agrofy.com.ar OR site:agrositio.com OR site:clarin.com OR site:lanacion.com OR site:bichosdecampo.com OR site:agrovoz.com.ar OR site:eldestapeweb.com';

const queriesEspeciales = {
  // Profertil: empresa de fertilizantes, búsqueda con términos de sector
  "Profertil":     '"Profertil" (fertilizante OR urea OR nitrogenado OR amoniaco OR agro OR campo OR produccion) ' + MEDIOS_ARG,
  // Apóstoles: hacienda láctea de Adecoagro — término específico del rubro
  "Apóstoles":     '"Apóstoles" (lacteo OR leche OR adecoagro OR hacienda OR yogur) ' + MEDIOS_ARG,
  // La Carolina: hacienda ganadera
  "La carolina":   '"La Carolina" (adecoagro OR hacienda OR bovino OR campo OR soja) ' + MEDIOS_ARG,
  // El Orden: estancia/campo
  "El Orden":      '"El Orden" (adecoagro OR campo OR agro OR misiones OR corrientes OR hacienda) ' + MEDIOS_ARG,
  // Angelita: campo/hacienda
  "Angelita":      '"Angelita" (adecoagro OR agro OR campo OR hacienda OR granja OR lacteo) ' + MEDIOS_ARG,
  // Simoneta: hacienda
  "Simoneta":      '"Simoneta" (adecoagro OR agro OR campo OR hacienda OR bovino) ' + MEDIOS_ARG,
  // Tether: SOLO nos interesa si habla de Adecoagro
  "tether":        '"Tether" adecoagro',
  // La Lácteo: planta procesadora de leche
  "La Lácteo":     '"La Lácteo" OR "La Lacteo" (adecoagro OR leche OR lacteo OR argentina) ' + MEDIOS_ARG,
  // Pilagá: ingenio azucarero
  "Pilagá":        '"Pilagá" OR "Pilaga" (azucar OR cana OR adecoagro OR campo OR ingenio OR agro) ' + MEDIOS_ARG,
};

const listaEmpresas = empresasString.split(',').map(e => e.trim());

return listaEmpresas.map(empresa => {
  const queryEspecial = queriesEspeciales[empresa] || queriesEspeciales[empresa.toLowerCase()];
  const query = queryEspecial || `"${empresa}" adecoagro OR agro campo argentina`;
  return {
    json: {
      empresa_asociada: empresa,
      query_busqueda_asociada: query,
      tipo_fuente: "web_asociada"
    }
  };
});

// ══════════════════════════════════════════════════════════════════════════════
// GENERADOR HTML — 3 secciones con estilo original
// Sección 1: Noticias principales (web)
// Sección 2: Redes Sociales (social) + treemap por red
// Sección 3: Empresas Asociadas (web_asociada) + acordeón por empresa
// ══════════════════════════════════════════════════════════════════════════════

// ── 1. PARSEAR OUTPUT DEL LLM ─────────────────────────────────────────────────
// sanitizeJson: reemplaza caracteres de control literales dentro de strings JSON.
// Maneja casos donde el LLM devuelve newlines u otros chars sin escapar en strings.
function sanitizeJson(s) {
  let out = '';
  let inStr = false;
  let i = 0;
  while (i < s.length) {
    const ch = s[i];
    if (inStr) {
      if (ch === '\\') {
        out += ch;
        if (i + 1 < s.length) { i++; out += s[i]; }
      } else if (ch === '"') {
        inStr = false;
        out += ch;
      } else if (ch.charCodeAt(0) < 32) {
        out += ' '; // reemplazar control chars con espacio
      } else {
        out += ch;
      }
    } else {
      if (ch === '"') inStr = true;
      out += ch;
    }
    i++;
  }
  return out;
}

// buildFallbackItems: construye items desde la respuesta cruda de Merge cuando
// el JSON del LLM no se puede parsear. Usa los datos originales del workflow.
function buildFallbackItems() {
  try {
    return $('Merge').all().map(i => ({
      titulo:      i.json.titulo || '',
      resumen:     (i.json.contenido || '').slice(0, 300),
      categoria:   i.json.tipo_fuente === 'social' ? 'Social'
                 : i.json.tipo_fuente === 'web_asociada' ? 'Empresas Asociadas'
                 : 'Marca Principal',
      sentimiento: 'Neutro',
      url_real:    i.json.url || '',
      medio:       '',
      fecha:       i.json.fecha || '',
      empresa:     i.json.empresa || '',
      tipo_fuente: i.json.tipo_fuente || 'web',
      es_red_social: i.json.tipo_fuente === 'social',
    }));
  } catch(e) { return []; }
}

let data = { resumen_noticias: '', resumen_social: '', resumen_empresas: '', items: [] };
try {
  const raw = items[0].json.content || items[0].json.message?.content || items[0].json.text || '';
  const stripped = (typeof raw === 'string') ? raw.replace(/```json/g,'').replace(/```/g,'').trim() : JSON.stringify(raw);
  // Intento 1: parseo directo
  let parsed = null;
  try { parsed = JSON.parse(stripped); } catch(e1) {}
  // Intento 2: parseo con sanitización de control chars
  if (!parsed) {
    try { parsed = JSON.parse(sanitizeJson(stripped)); } catch(e2) {}
  }
  if (parsed) {
    data = parsed;
  } else {
    // Fallback: usar items del nodo Merge directamente
    data.items = buildFallbackItems();
    data.resumen_noticias = '(Análisis automático no disponible — mostrando artículos sin clasificar)';
  }
} catch(e) {
  data.items = buildFallbackItems();
  data.resumen_noticias = '(Análisis automático no disponible)';
}

const allItems   = data.items || [];
const fechaHoy       = new Date().toLocaleString('es-AR', { timeZone: 'America/Argentina/Buenos_Aires' });
const fechaSolo      = new Date().toLocaleDateString('es-AR', { timeZone: 'America/Argentina/Buenos_Aires', day: '2-digit', month: 'long', year: 'numeric' });
let   totalAnalizadas = 0;
try { totalAnalizadas = $('Merge').all().length; } catch(e) {}
if (!totalAnalizadas) totalAnalizadas = allItems.length;

// ── 2. SEPARAR POR TIPO DE FUENTE ─────────────────────────────────────────────
// itemsWeb: el upstream (Aplanar Resultados) ya garantiza que el artículo
// menciona Adecoagro. No re-filtramos aquí para no perder artículos cuyo
// resumen de IA no repite explícitamente el nombre de la empresa.
const itemsWeb      = allItems.filter(i =>
  i.tipo_fuente === 'web' ||
  (!i.tipo_fuente && i.categoria !== 'Social' && i.categoria !== 'Empresas Asociadas')
);
const itemsSocial   = allItems.filter(i => i.tipo_fuente === 'social'       || i.es_red_social === true || i.categoria === 'Social');
const itemsEmpresas = allItems.filter(i =>
  (i.tipo_fuente === 'web_asociada' || i.categoria === 'Empresas Asociadas') &&
  i.empresa && !['desconocida', 'unknown', 'n/a', ''].includes((i.empresa||'').toLowerCase().trim())
);

// ── 3. ESTADÍSTICAS POR SECCIÓN ───────────────────────────────────────────────
const calcStats = (arr) => ({
  pos: arr.filter(i => (i.sentimiento||'').toLowerCase().includes('pos')).length,
  neu: arr.filter(i => (i.sentimiento||'').toLowerCase() === 'neutro' || !(i.sentimiento||'').toLowerCase().includes('pos') && !(i.sentimiento||'').toLowerCase().includes('neg')).length,
  neg: arr.filter(i => (i.sentimiento||'').toLowerCase().includes('neg')).length,
});
const stW = calcStats(itemsWeb);
const stS = calcStats(itemsSocial);
const stE = calcStats(itemsEmpresas);

// Top fuentes de cobertura (reemplaza menciones por marca)
const fuenteCount = {};
itemsWeb.forEach(i => {
  const raw = i.medio || (i.url_real||i.url||'')
    .replace(/https?:\/\/(www\.)?/,'').split('/')[0].split('.')[0] || 'Otro';
  const label = raw.charAt(0).toUpperCase() + raw.slice(1).toLowerCase();
  fuenteCount[label] = (fuenteCount[label]||0) + 1;
});
const topFuentes = Object.entries(fuenteCount).sort((a,b)=>b[1]-a[1]).slice(0,6);

// Conteo por red social
const detectRed = (url='') => {
  const u = url.toLowerCase();
  if (u.includes('instagram.com')) return 'Instagram';
  if (u.includes('facebook.com'))  return 'Facebook';
  if (u.includes('tiktok.com'))    return 'TikTok';
  if (u.includes('youtube.com'))   return 'YouTube';
  if (u.includes('threads.net'))   return 'Threads';
  // Twitter/X: match preciso para evitar falsos positivos con dominios que contienen 'x.com'
  if (u.includes('twitter.com') || /[\/.]x\.com[\/]/.test(u) || u.includes('//x.com')) return 'Twitter/X';
  if (u.includes('linkedin.com'))  return 'LinkedIn';
  return 'Otros';
};
const redesCount = {};
itemsSocial.forEach(i => {
  const red = detectRed(i.url_real || i.url || '');
  redesCount[red] = (redesCount[red]||0) + 1;
});
const redesEntries = Object.entries(redesCount).sort((a,b)=>b[1]-a[1]);

// Agrupar empresas asociadas
const empresaMap = {};
itemsEmpresas.forEach(i => {
  const emp = i.empresa || 'Sin clasificar';
  if (!empresaMap[emp]) empresaMap[emp] = [];
  empresaMap[emp].push(i);
});
const empresasOrdenadas = Object.entries(empresaMap).sort((a,b)=>b[1].length-a[1].length);


// ── 4. HELPERS HTML ───────────────────────────────────────────────────────────
const sentKey = (s) => {
  const sl = (s||'').toLowerCase();
  return sl.includes('pos') ? 'positivo' : sl.includes('neg') ? 'negativo' : 'neutro';
};
const badgeClass = (s) => sentKey(s) === 'positivo' ? 'bg-positivo' : sentKey(s) === 'negativo' ? 'bg-negativo' : 'bg-neutro';

// ── 4b. EXTRA STATS HELPERS ──────────────────────────────────────────────────
const topFuentesHtml = topFuentes.map(([m,n]) =>
  `<div class="stat-line">${m} <span class="stat-val">${n}</span></div>`).join('');

// ── 4c. ITEM HTML HELPERS (new design) ────────────────────────────────────────

const noticiaHTML = (item, prefix='') => {
  const url   = item.url_real || item.url || '#';
  const medio = item.medio || (url !== '#' ? url.replace(/https?:\/\/(www\.)?/,'').split('/')[0] : 'Fuente');
  const fecha = item.fecha || 'Hoy';
  const sk    = sentKey(item.sentimiento);
  const bc    = sk === 'positivo' ? 'badge-pos' : sk === 'negativo' ? 'badge-neg' : 'badge-neu';
  const lc    = sk === 'positivo' ? 'var(--pos)' : sk === 'negativo' ? 'var(--neg)' : 'var(--neu)';
  const mentionsAdec = ((item.titulo||'')+' '+(item.resumen||'')).toLowerCase().includes('adecoagro');
  return `<li class="article-item" data-sentimiento="${sk}" data-prefix="${prefix}">
    <div class="article-title"><a href="${url}" target="_blank">${item.titulo || 'Sin título'}</a></div>
    <div class="article-meta">
      <span class="article-time">${fecha} · ${medio}</span>
      <span class="badge ${bc}">${item.sentimiento || 'Neutro'}</span>
      ${mentionsAdec ? '<span class="badge badge-adec">ADECOAGRO</span>' : ''}
    </div>
    <a href="${url}" target="_blank" class="article-link" style="color:${lc}">Leer noticia →</a>
  </li>`;
};

// Ordenar por sentimiento: pos → neu → neg
const sortBySent = arr => [...arr].sort((a,b) => {
  const r = s => sentKey(s) === 'positivo' ? 0 : sentKey(s) === 'negativo' ? 2 : 1;
  return r(a.sentimiento) - r(b.sentimiento);
});

const htmlWeb = sortBySent(itemsWeb).map(i => noticiaHTML(i,'web')).join('');

const colorRed = (red) => ({
  'Instagram':'#E1306C','Facebook':'#1877F2','TikTok':'#69C9D0',
  'YouTube':'#FF0000','Threads':'#101010','Twitter/X':'#1DA1F2',
  'LinkedIn':'#0077B5','Otros':'#777'
}[red]||'#777');

const htmlSocial = sortBySent(itemsSocial).map(item => {
  const url = item.url_real || item.url || '#';
  const red = detectRed(url);
  const col = colorRed(red);
  const sk  = sentKey(item.sentimiento);
  const bc  = sk === 'positivo' ? 'badge-pos' : sk === 'negativo' ? 'badge-neg' : 'badge-neu';
  return `<li class="article-item" data-sentimiento="${sk}" data-prefix="soc" style="border-left-color:${col}">
    <div class="article-title"><a href="${url}" target="_blank" style="color:${col}">${item.titulo||'Sin título'}</a></div>
    <div class="article-meta">
      <span class="article-time">${item.fecha||'Hoy'}</span>
      <span class="platform-tag" style="background:${col}">${red}</span>
      <span class="badge ${bc}">${item.sentimiento||'Neutro'}</span>
    </div>
    <a href="${url}" target="_blank" class="article-link" style="color:${col}">Ver en ${red} →</a>
  </li>`;
}).join('');

const getDomain = (url='') => (url||'').replace(/https?:\/\/(www\.)?/,'').split('/')[0].toLowerCase();

const htmlEmpresas = empresasOrdenadas.map(([emp, empItems]) => {
  const seenDomains = new Set();
  empItems = empItems.filter(i => {
    const d = getDomain(i.url_real || i.url);
    if (!d || seenDomains.has(d)) return false;
    seenDomains.add(d);
    return true;
  }).slice(0, 3);
  const ep = empItems.filter(i=>sentKey(i.sentimiento)==='positivo').length;
  const en = empItems.filter(i=>sentKey(i.sentimiento)==='negativo').length;
  const dotColor = en > ep ? 'var(--neg)' : ep > en ? 'var(--pos)' : 'var(--neu)';
  return `<details class="empresa-accordion">
    <summary>
      <span style="width:8px;height:8px;border-radius:50%;background:${dotColor};display:inline-block;flex-shrink:0"></span>
      <span class="empresa-name">${emp}</span>
      <span class="empresa-badge">${empItems.length} art.</span>
    </summary>
    <div style="padding:14px 18px">
      <ul class="article-list">
        ${sortBySent(empItems).map(i=>noticiaHTML(i,'emp')).join('')}
      </ul>
    </div>
  </details>`;
}).join('');

// Arrays Chart.js
const arrSentWeb  = `[${stW.pos},${stW.neu},${stW.neg}]`;
const arrSentEmp  = `[${stE.pos},${stE.neu},${stE.neg}]`;
const arrSentSoc  = `[${stS.pos},${stS.neu},${stS.neg}]`;
const treemapData = JSON.stringify(redesEntries.map(([g,v])=>({ v, g })));
const treemapBgs  = JSON.stringify(redesEntries.map(([l]) => colorRed(l)));
const fuenteLabelsJson = JSON.stringify(topFuentes.map(([m])=>m));
const fuenteValsJson   = JSON.stringify(topFuentes.map(([,n])=>n));

// ── 5. HTML COMPLETO — diseño Adecoagro dark (verde + lima) ──────────────────
