<script>
Chart.register(ChartDataLabels);
Chart.defaults.font.family = "'IBM Plex Mono', monospace";
Chart.defaults.color = '#5A8A6A';
const LIME = '#D0F921';
const POS  = '#3FB882';
const NEU  = '#C9A84C';
const NEG  = '#E05555';
const sentColors = [POS, NEU, NEG];
const donutOpts = () => ({
  maintainAspectRatio: false, cutout: '65%',
  plugins: {
    legend: { position: 'right', labels: { color: '#5A8A6A', font:{size:11}, padding:14, boxWidth:10, boxHeight:10, usePointStyle:true } },
    datalabels: { color: '#fff', font:{weight:'bold',size:12}, formatter: v => v > 0 ? v : '' }
  }
});
new Chart(document.getElementById('chartWebSent'), {
  type:'doughnut',
  data:{ labels:['Positivo','Neutro','Negativo'], datasets:[{ data:${arrSentWeb}, backgroundColor:sentColors, borderWidth:0, hoverOffset:6 }] },
  options: donutOpts()
});
const fuenteLabels = ${fuenteLabelsJson};
const fuenteVals   = ${fuenteValsJson};
if (fuenteLabels.length > 0) {
  new Chart(document.getElementById('chartMarcas'), {
    type:'bar',
    data:{ labels:fuenteLabels, datasets:[{ data:fuenteVals, backgroundColor:LIME, barPercentage:0.55 }] },
    options:{ maintainAspectRatio:false, indexAxis:'y', plugins:{ legend:{display:false}, datalabels:{anchor:'end',align:'end',color:'#5A8A6A',font:{size:11}} }, scales:{ x:{display:false,grace:'20%'}, y:{grid:{display:false},ticks:{color:'#5A8A6A',font:{size:10}}} } }
  });
}
const treeData = ${treemapData};
const treeBgs  = ${treemapBgs};
if (treeData.length > 0) {
  new Chart(document.getElementById('chartTreemap'), {
    type:'treemap',
    data:{ datasets:[{ tree:treeData, key:'v', groups:['g'], backgroundColor: ctx => treeBgs[ctx.dataIndex]||'#555', labels:{ display:true, formatter: ctx => ctx.raw.g ? [ctx.raw.g, ctx.raw.v] : '', color:'#fff', font:[{size:13,weight:'bold'},{size:11}] } }] },
    options:{ maintainAspectRatio:false, plugins:{ legend:{display:false}, datalabels:{display:false} } }
  });
}
new Chart(document.getElementById('chartSocSent'), {
  type:'doughnut',
  data:{ labels:['Positivo','Neutro','Negativo'], datasets:[{ data:${arrSentSoc}, backgroundColor:sentColors, borderWidth:0, hoverOffset:6 }] },
  options: donutOpts()
});
if (document.getElementById('chartEmpSent')) {
  new Chart(document.getElementById('chartEmpSent'), {
    type:'doughnut',
    data:{ labels:['Positivo','Neutro','Negativo'], datasets:[{ data:${arrSentEmp}, backgroundColor:sentColors, borderWidth:0, hoverOffset:6 }] },
    options: donutOpts()
  });
}
if (document.getElementById('chartEmpVol')) {
  const empLabels = ${JSON.stringify(empresasOrdenadas.map(([e])=>e))};
  const empVals   = ${JSON.stringify(empresasOrdenadas.map(([,a])=>a.length))};
  new Chart(document.getElementById('chartEmpVol'), {
    type:'bar',
    data:{ labels:empLabels, datasets:[{ data:empVals, backgroundColor:LIME, barPercentage:0.5 }] },
    options:{ maintainAspectRatio:false, indexAxis:'y', plugins:{ legend:{display:false}, datalabels:{anchor:'end',align:'end',color:'#5A8A6A',font:{size:11}} }, scales:{ x:{display:false,grace:'20%'}, y:{grid:{display:false},ticks:{color:'#5A8A6A',font:{size:11}}} } }
  });
}
function filtrar(prefix, sentimiento, btn) {
  document.querySelectorAll('[data-prefix="'+prefix+'"]').forEach(el => {
    el.classList.toggle('oculto', sentimiento !== 'all' && el.dataset.sentimiento !== sentimiento);
  });
  btn.closest('.filter-bar').querySelectorAll('.filter-btn').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
}
const sections = document.querySelectorAll('section[id]');
const navLinks  = document.querySelectorAll('.nav-link');
const observer  = new IntersectionObserver(entries => {
  entries.forEach(e => {
    if (e.isIntersecting) {
      navLinks.forEach(l => l.classList.remove('active'));
      const a = document.querySelector('.nav-link[href="#'+e.target.id+'"]');
      if (a) a.classList.add('active');
    }
  });
}, { rootMargin: '-30% 0px -60% 0px' });
sections.forEach(s => observer.observe(s));
<\/script>
</body>
</html>`;
const binaryData = Buffer.from(html, 'utf8').toString('base64');
return [{
  json: { asunto: `Reporte Adecoagro: ${allItems.length} ítems (${itemsWeb.length} noticias · ${itemsSocial.length} social · ${itemsEmpresas.length} empresas)` },
  binary: { data: { data: binaryData, mimeType: 'text/html', fileName: 'reporte_adecoagro.html' } }
}];

// ── DEDUPLICAR (dedup en memoria, cross-branch) ──────────────────────────────
// Une los items de las 3 ramas (Noticias, Social, Empresas) y elimina duplicados.
// Usa content_hash como clave principal; fallback a URL si no hay hash.
// NUEVO: dedup por título normalizado — filtra la misma noticia en dos URLs distintas.
// ─────────────────────────────────────────────────────────────────────────────

// Normaliza un título para comparar: minúsculas, sin tildes, sin puntuación
const normTitle = (s) => (s||'').toLowerCase()
  .normalize('NFD').replace(/[̀-ͯ]/g,'')
  .replace(/[^\w\s]/g,'').replace(/\s+/g,' ').trim();

// Porcentaje de palabras (>3 chars) en común entre dos títulos
const titleSimilarity = (a, b) => {
  const wa = new Set(normTitle(a).split(' ').filter(w => w.length > 3));
  const wb = new Set(normTitle(b).split(' ').filter(w => w.length > 3));
  if (!wa.size || !wb.size) return 0;
  let common = 0;
  for (const w of wa) if (wb.has(w)) common++;
  return common / Math.min(wa.size, wb.size);
};

const seen    = new Set();   // hashes/URLs vistos
const result  = [];          // items que pasan
const titles  = [];          // títulos ya incluidos (para comparar similitud)

for (const item of $input.all()) {
  const url   = item.json.url || item.json.link || '';
  const hash  = item.json.content_hash || item.json.hash || '';
  const key   = hash || url;
  const title = item.json.titulo || item.json.title || '';

  // 1. Dedup por hash/URL
  if (key && seen.has(key)) continue;

  // 2. Dedup por similitud de título (umbral 0.75)
  const esDuplicadoPorTitulo = titles.some(t => titleSimilarity(title, t) >= 0.75);
  if (esDuplicadoPorTitulo) continue;

  if (key) seen.add(key);
  titles.push(title);
  result.push(item);
}

return result;

// ── FILTRAR NUEVAS (dedup contra Postgres, últimos 60 días) ──────────────────
// Compara los items del Merge contra los hashes ya almacenados en la DB.
// Solo pasan los items que NO están en la DB → evita re-procesar noticias viejas.
// Input:  filas de Consultar Postgres (url_hash, content_hash)
// Origen: $('Deduplicar').all() — los items ya deduplicados en memoria
// ─────────────────────────────────────────────────────────────────────────────

// 1. Construir set de hashes ya almacenados en Postgres
const hashesEnDB = new Set();
for (const row of $input.all()) {
  if (row.json.url_hash)     hashesEnDB.add(row.json.url_hash);
  if (row.json.content_hash) hashesEnDB.add(row.json.content_hash);
}

// 2. Filtrar: conservar solo items cuyo hash NO esté en la DB
const itemsDeduplicados = $('Deduplicar').all();

return itemsDeduplicados.filter(item => {
  const hash = item.json.content_hash || item.json.hash || '';
  // Sin hash → dejar pasar (no podemos comparar, mejor procesar que perder)
  if (!hash) return true;
  return !hashesEnDB.has(hash);
});

// ── SPLIT QUERIES NEWS ─────────────────────────────────────────────────────────
// 5 queries dirigidas. TODAS requieren Adecoagro explícito.
// SIN comillas dobles en el texto — se interpolan en el JSON body de Serper
// y las comillas dobles romperían el JSON.
// ─────────────────────────────────────────────────────────────────────────────

const empresa = $('Config').item.json.empresa || 'Adecoagro';

return [
  // Ángulo 1: medios argentinos especializados (prioridad editorial)
  { json: { query: empresa + ' site:infobae.com OR site:lanacion.com OR site:cronista.com OR site:ambito.com OR site:clarin.com OR site:agrofy.com.ar OR site:agrositio.com' } },
  // Ángulo 2: noticias financieras / bolsa / inversores
  { json: { query: empresa + ' acciones ADR inversor resultado dividendo bolsa argentina' } },
  // Ángulo 3: operacional / producción / campo
  { json: { query: empresa + ' cosecha produccion azucar leche campo expansion adquisicion' } },
  // Ángulo 4: cobertura general reciente (captura menciones inesperadas)
  { json: { query: empresa + ' noticias' } },
  // Ángulo 5: medios internacionales / financieros globales
  { json: { query: empresa + ' site:bloomberg.com OR site:reuters.com OR site:seekingalpha.com OR site:finance.yahoo.com OR site:businesswire.com' } },
];

// Lee los feeds RSS desde Config y genera un item por URL
const feedsStr = $('Config').item.json.rss_feeds || '';
return feedsStr
  .split(',')
  .map(u => u.trim())
  .filter(Boolean)
  .map(url => ({ json: { feed_url: url } }));

// ── NORMALIZAR RSS ─────────────────────────────────────────────────────────
// Parsea XML de feeds RSS, filtra items que mencionan "Adecoagro",
// normaliza al mismo formato que Aplanar Resultados (tipo_fuente: 'rss').
// ──────────────────────────────────────────────────────────────────────────

const normalizar = (s) => (s||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');

function extractTag(xml, tag) {
  const re = new RegExp('<' + tag + '[^>]*>(?:<!\\[CDATA\\[)?([\\s\\S]*?)(?:\\]\\]>)?<\\/' + tag + '>', 'i');
  const m = xml.match(re);
  return m ? m[1].trim() : '';
}

function extractLink(xml) {
  // <link>url</link> o <link href="url"/>
  let m = xml.match(/<link[^>]*>(?:<!\[CDATA\[)?(https?:\/\/[^\]<\s]+)(?:\]\]>)?<\/link>/i);
  if (m) return m[1].trim();
  m = xml.match(/<link[^>]+href="(https?:\/\/[^"]+)"/i);
  if (m) return m[1].trim();
  return '';
}

function stripHtml(s) {
  return (s||'').replace(/<[^>]+>/g, ' ').replace(/\s+/g,' ').trim();
}

function hashStr(s) {
  let h = 2166136261;
  for (let i = 0; i < s.length; i++) { h ^= s.charCodeAt(i); h = (h * 16777619) >>> 0; }
  return h.toString(16);
}

const sitiosPrioritarios = ($('Config').item.json.sitios_prioritarios || '')
  .split(',').map(d => d.trim()).filter(Boolean);

const results = [];
const seenUrls = new Set();

for (const item of $input.all()) {
  const xmlText = item.json.data || item.json.body || '';
  if (!xmlText) continue;

  const itemBlocks  = xmlText.match(/<item[\s\S]*?<\/item>/gi)   || [];
  const entryBlocks = xmlText.match(/<entry[\s\S]*?<\/entry>/gi) || [];

  for (const block of [...itemBlocks, ...entryBlocks]) {
    const title   = extractTag(block, 'title');
    const link    = extractLink(block) || extractTag(block, 'link') || extractTag(block, 'id');
    const desc    = stripHtml(extractTag(block, 'description') || extractTag(block, 'content') || extractTag(block, 'summary'));
    const pubDate = extractTag(block, 'pubDate') || extractTag(block, 'published') || extractTag(block, 'updated') || 'Reciente';

    if (!link || !link.startsWith('http')) continue;
    if (seenUrls.has(link)) continue;

    // FILTRO PRINCIPAL: debe mencionar "adecoagro"
    const texto = normalizar(title + ' ' + desc);
    if (!texto.includes('adecoagro')) continue;

    seenUrls.add(link);
    const esPrioritario = sitiosPrioritarios.some(d => link.includes(d));

    results.push({ json: {
      url:           link,
      title:         title,
      snippet:       desc.slice(0, 500),
      source:        'RSS',
      date:          pubDate,
      tipo_fuente:   'rss',
      es_prioritario: esPrioritario,
      es_financial:  false,
      content_hash:  'rss_' + hashStr(link),
    }});
  }
}

results.sort((a, b) => (b.json.es_prioritario ? 1 : 0) - (a.json.es_prioritario ? 1 : 0));
return results;
